const a="provider_models_cache";function o(t){try{const e=localStorage.getItem(a);if(!e)return null;const c=JSON.parse(e)[t];return c?{models:c.models,timestamp:c.timestamp,isExpired:Date.now()-c.timestamp>3e5}:null}catch(e){return console.error("Failed to get cached models:",e),null}}function s(t,e){try{const r=localStorage.getItem(a),c=r?JSON.parse(r):{};c[t]={models:e,timestamp:Date.now()},localStorage.setItem(a,JSON.stringify(c))}catch(r){console.error("Failed to cache models:",r)}}function n(t){const e=o(t);return e?e.isExpired?{status:"stale",message:"Данные устарели"}:{status:"fresh",message:"Актуальные данные"}:{status:"none",message:"Нет кэша"}}function l(){try{localStorage.removeItem(a)}catch(t){console.error("Failed to clear all cache:",t)}}export{s as a,l as c,n as g};
